public boolean evenlySpaced(int a, int b, int c)
{
    int spacing;
        if (a>b)
        {
            spacing = a;
    		a = b;
            b = spacing;
        }
    	else if ( b > c)
        {
         	spacing = b;
            b = c;
            c = spacing;
        }
    	else if (a>b)
        {
         spacing = a;
            a = b;
            b = spacing;
        }
    	return b-a == c-b;
}

def make_chocolate(small, big, goal):
{
    if goal >= 5 * big:
    {
        remainder = goal - 5 * big
    }
    else:
    {
        remainder = goal % 5
    }

    if remainder <= small:
    {
        return remainder
    }
    return -1
}

public int countCode(String str)
{
  	int count = 0;
    int len = str.length();
    for (int i = 0; i < len - 3; i++)
    {
        int iCo = str.indexOf("co", i);
        if (iCo!= -1) 
        {
        String code = str.substring(iCo, iCo+4);
        if (code.endsWith("e"))
            count++;
        }
    }
    return count;
}

