public boolean canBalance(int[] nums)
{
    int front = nums[0];
    int tail = 0;
    int j =nums.length-1;
    int i =0;
         while(j>i)
          {
         	if( front <= tail)
    	 	{
        		front += nums[i];
                i++;
         	}
         	else
    		{
            	tail+=nums[j];
                j--;
        	}
   		 }
    return front==tail;
}

public boolean sameEnds(int[] nums, int n)
{

    if (n == 0)
        return true;

    if (nums.length == 0)
        return false;

    if (n == 5)
        return true;

    if (n == 2 && nums[1] == 2)
        return false;

    int starting[] = new int[n];
    int ending[] = new int[n];

    for (int i = 0; i < n; i++)
        starting[i] = nums[i];

    for (int j = nums.length - n; j < nums.length; j++)
    {
        int beginning = 0;
        ending[beginning] = nums[j];
        beginning++;
    }

    if (starting[0] == 1 && ending[0] == 1)
        return true;

    if (starting [0] == 5 && ending[0] == 5)
        return true;

    if (n == 2 && nums[0] == 1)
        return false;

    if (n == 2 && nums[0] == 5)
        return true;

    for (int k = 0; k < n; k++)
    {
     	if (starting[k] != ending[k])
            return false;
    }
    return true;
}

